            //
            aOrbiterE = ((aOrbiterE + aOrbiterG) + 18029699867733207083U) + aNonceWordG;
            aOrbiterC = (aOrbiterC ^ aOrbiterE) ^ 13361836994951253312U;
            aOrbiterC = RotL64((aOrbiterC * 5349767426256597073U), 5U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterB) + 11957294454794128079U;
