            aOrbiterD = RotL64((aOrbiterD * 13896364063651241401U), 11U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 18001157153447913032U;
            aOrbiterB = (((aOrbiterB ^ aOrbiterF) ^ 16214145724690286854U) ^ aOrbiterUpdateSaltE[((aIndex + 5U)) & S_SALT1]) ^ aNonceWordJ;
            aOrbiterB = RotL64((aOrbiterB * 5874139687703360515U), 27U);
