            aIngress = RotL64(aScrapLaneA[((aIndex + 9355U)) & S_BLOCK1], 43U) ^ RotL64(aSource[((aIndex + 10921U)) & S_BLOCK1], 11U);
            aIngress = TwistMix64::DiffuseC(((aIngress ^ aDomainWordIngress) ^ aNonceWordP));
            //
            aCross = RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 10535U)) & S_BLOCK1], 53U) ^ RotL64(pSnow[((S_BLOCK1 - aIndex + 6922U)) & S_BLOCK1], 4U);
            aCross = TwistMix64::DiffuseA(((aCross ^ aDomainWordCross) ^ aNonceWordI));
