            aOrbiterE = ((aWandererK + RotL64(aIngress, 34U)) + RotL64(aCarry, 27U)) + 12294016745653004819U;
            aOrbiterH = ((aWandererG + RotL64(aPrevious, 51U)) + 18269588932920281147U) + aOrbiterAssignSaltC[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterG = (aWandererI + RotL64(aScatter, 41U)) + 5872406424994751026U;
