            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 7845523921295625315U;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 12742115479740024747U;
            aOrbiterG = RotL64((aOrbiterG * 15578543510683986421U), 19U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 10294667720904610944U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterH) ^ 14369711143154904567U) ^ aNonceWordO;
            aOrbiterF = RotL64((aOrbiterF * 13753005602288309379U), 13U);
            //
            aOrbiterI = (((aOrbiterI + aOrbiterD) + 10918344717497681894U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 15U)) & S_SALT1]) + aNonceWordG;
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 18136794828308636957U;
            aOrbiterE = RotL64((aOrbiterE * 17899418637978002409U), 37U);
